class IoTDevice(private val ipAddress: String, private val httpClient: IoTHttpClient) {
    
    fun getStatus(callback: IoTHttpClient.HttpCallback) {
        httpClient.get("http://$ipAddress/api/status", callback)
    }

    fun sendCommand(command: String, params: Map<String, Any>, callback: IoTHttpClient.HttpCallback) {
        val json = JSONObject().apply {
            put("command", command)
            put("params", JSONObject(params))
        }.toString()
        
        httpClient.post("http://$ipAddress/api/command", json, callback)
    }

    fun updateConfig(config: Map<String, Any>, callback: IoTHttpClient.HttpCallback) {
        val json = JSONObject(config).toString()
        httpClient.put("http://$ipAddress/api/config", json, callback)
    }
}

